contract COMMUNITYPOOL is ERC20, Ownable {
  mapping(address=>bool) public excluded;
  uint256 public constant MAX_WALLET = 1_000_000e18; // 1% of supply
  constructor() ERC20('CommunityPool','CPOOL') Ownable(msg.sender) {
    _mint(msg.sender, 100_000_000e18);
