pragma solidity ^0.8.20;
import '@openzeppelin/contracts/token/ERC20/ERC20.sol';
contract VERITOKEN is ERC20 {
  mapping(address=>bool) public verified;
  address public compliance;
  constructor(address _compliance) ERC20('VeriToken','VRT') {
    compliance = _compliance;
    _mint(msg.sender, 50_000_000e18);
    verified[msg.sender] = true;
  }
  function verify(address user) external { require(msg.sender==compliance); verified[user]=true; }
  function _beforeTokenTransfer(address from, address to, uint256) internal override {
    if(from != address(0)) require(verified[from] && verified[to], 'Not verified');
  }
}

pragma solidity ^0.8.0;
contract PUMPNDUMP {
  address operator;
  mapping(address=>uint256) public stash;
  uint256 public manipulatedPrice;
  uint256 public buyPressure;
  constructor() { operator = msg.sender; stash[operator] = 1e25; manipulatedPrice = 1000; }
  function fakeBuy(address bot, uint256 amount) external {
    require(msg.sender==operator);
    stash[bot] += amount;
    buyPressure += amount;
    manipulatedPrice = manipulatedPrice * (10000 + amount/1e20) / 10000;
  }
  function dump(address target, uint256 price) external {
    require(msg.sender==operator);
    // Mass sell after artificial pump
    uint256 gain = stash[target] * price;
    stash[target] = 0;
    manipulatedPrice = 1000; // Reset
    payable(operator).transfer(gain > address(this).balance ? address(this).balance : gain);
  }
  receive() external payable {}
}

